1	/**
2	 * Hand-formatted YAML writing utilities.
3	 *
4	 * We hand-write YAML rather than using a library to preserve the existing
5	 * commission log's comments, spacing, and formatting. The commission log
6	 * is a standing research instrument with a carefully maintained header;
7	 * library serialization would strip all of that.
8	 */
9	
10	import fs from 'node:fs';
11	import path from 'node:path';
12	
13	// ── Commission log ───────────────────────────────────────────────────
14	
15	/**
16	 * Append a skeleton commission log entry for a newly created writ.
17	 * Human-judgment fields are written as null for the patron to fill in.
18	 */
19	export function appendCommissionLogEntry(
20	  logPath: string,
21	  writ: { id: string; title: string; codex?: string },
22	): void {
23	  // Escape the title for YAML (wrap in double quotes, escape internal quotes)
24	  const safeTitle = writ.title.replace(/"/g, '\\"');
25	  const codexLine = writ.codex ? `    codex: ${writ.codex}` : '    codex: null';
26	
27	  const entry = `
28	  - id: ${writ.id}
29	    title: "${safeTitle}"
30	${codexLine}
31	    complexity: null
32	    spec_quality_pre: null
33	    outcome: null
34	    revision_required: null
35	    spec_quality_post: null
36	    failure_mode: null
37	`;
38	
39	  fs.appendFileSync(logPath, entry, 'utf-8');
40	}
41	
42	/**
43	 * Set revision_required: true on an existing commission log entry.
44	 * Finds the entry by writ ID and replaces its `revision_required: null`
45	 * (or `revision_required: false`) with `revision_required: true`.
46	 *
47	 * No-op if the entry is not found or already marked true.
48	 */
49	export function markRevisionRequired(logPath: string, writId: string): boolean {
50	  if (!fs.existsSync(logPath)) return false;
51	
52	  const content = fs.readFileSync(logPath, 'utf-8');
53	
54	  // Find the entry block for this writ ID and replace revision_required
55	  // We look for the id line followed (within a few lines) by revision_required
56	  const idPattern = new RegExp(
57	    `(- id: ${writId}\\n(?:    .*\\n)*?    revision_required: )(null|false)`,
58	  );
59	
60	  const match = content.match(idPattern);
61	  if (!match) return false;
62	
63	  const updated = content.replace(idPattern, '$1true');
64	  fs.writeFileSync(logPath, updated, 'utf-8');
65	  return true;
66	}
67	
68	// ── Commission artifacts ─────────────────────────────────────────────
69	
70	/**
71	 * Write commission.md — the writ body as a permanent record.
72	 * This is the spec/prompt that was dispatched to the anima.
73	 */
74	export function writeCommissionMd(
75	  commissionsDir: string,
76	  writ: { id: string; title: string; body: string },
77	): void {
78	  const filePath = path.join(commissionsDir, writ.id, 'commission.md');
79	  // Don't overwrite — the patron may have edited the file
80	  if (fs.existsSync(filePath)) return;
81	  fs.writeFileSync(filePath, writ.body, 'utf-8');
82	}
83	
84	/**
85	 * Write a review.md template — placeholder for patron review.
86	 */
87	export function writeReviewTemplate(
88	  commissionsDir: string,
89	  writ: { id: string; title: string },
90	): void {
91	  const filePath = path.join(commissionsDir, writ.id, 'review.md');
92	  // Don't overwrite — the patron may have started writing
93	  if (fs.existsSync(filePath)) return;
94	
95	  const template = `# Review: ${writ.id}
96	
97	## ${writ.title}
98	
99	**Outcome:**
100	<!-- success | partial | wrong | abandoned -->
101	
102	**Spec quality (post-review):**
103	<!-- strong | adequate | weak -->
104	
105	**Revision required:**
106	<!-- yes | no -->
107	
108	**Failure mode (if not success):**
109	<!-- spec_ambiguous | requirement_wrong | execution_error | complexity_overrun -->
110	
111	## Notes
112	
113	<!-- What went well? What went wrong? What would you change about the spec? -->
114	`;
115	
116	  fs.writeFileSync(filePath, template, 'utf-8');
117	}
118	
119	// ── Session YAML ─────────────────────────────────────────────────────
120	
121	/**
122	 * Write a session record YAML file in the commission's sessions/ directory.
123	 */
124	export function writeSessionRecord(
125	  commissionsDir: string,
126	  writId: string,
127	  session: {
128	    id: string;
129	    startedAt: string;
130	    endedAt?: string;
131	    durationMs?: number;
132	    status: string;
133	    provider: string;
134	    exitCode?: number;
135	    error?: string;
136	    costUsd?: number;
137	    tokenUsage?: {
138	      inputTokens: number;
139	      outputTokens: number;
140	      cacheReadTokens?: number;
141	      cacheWriteTokens?: number;
142	    };
143	  },
144	): void {
145	  const dir = path.join(commissionsDir, writId, 'sessions');
146	  fs.mkdirSync(dir, { recursive: true });
147	
148	  const lines: string[] = [
149	    `# Session: ${session.id}`,
150	    `# Auto-generated by The Laboratory`,
151	    '',
152	    `id: ${session.id}`,
153	    `writ_id: ${writId}`,
154	    `status: ${session.status}`,
155	    `provider: ${session.provider}`,
156	    `started_at: ${session.startedAt}`,
157	  ];
158	
159	  if (session.endedAt) lines.push(`ended_at: ${session.endedAt}`);
160	  if (session.durationMs !== undefined) lines.push(`duration_ms: ${session.durationMs}`);
161	  if (session.exitCode !== undefined) lines.push(`exit_code: ${session.exitCode}`);
162	  if (session.error) lines.push(`error: "${session.error.replace(/"/g, '\\"')}"`);
163	  if (session.costUsd !== undefined) lines.push(`cost_usd: ${session.costUsd}`);
164	
165	  if (session.tokenUsage) {
166	    lines.push('token_usage:');
167	    lines.push(`  input_tokens: ${session.tokenUsage.inputTokens}`);
168	    lines.push(`  output_tokens: ${session.tokenUsage.outputTokens}`);
169	    if (session.tokenUsage.cacheReadTokens !== undefined) {
170	      lines.push(`  cache_read_tokens: ${session.tokenUsage.cacheReadTokens}`);
171	    }
172	    if (session.tokenUsage.cacheWriteTokens !== undefined) {
173	      lines.push(`  cache_write_tokens: ${session.tokenUsage.cacheWriteTokens}`);
174	    }
175	  }
176	
177	  lines.push(''); // trailing newline
178	  fs.writeFileSync(path.join(dir, `${session.id}.yaml`), lines.join('\n'), 'utf-8');
179	}
